using Microsoft.AspNetCore.Http.HttpResults;
using Npgsql;

namespace eShop.Catalog.API.Apis;

public static class ShippingRatesApi
{
    public static RouteGroupBuilder MapShippingRatesApi(this IEndpointRouteBuilder app)
    {
        var api = app.MapGroup("api/shipping");

        api.MapGet("/rates", GetShippingRates);
        api.MapGet("/rates/{carrier}", GetRatesByCarrier);
        api.MapGet("/estimate", GetShippingEstimate);

        return api;
    }

    public static async Task<Ok<List<ShippingRate>>> GetShippingRates(
        decimal? minWeight,
        decimal? maxWeight,
        string? zone)
    {
        // Query the ordering database for shipping rates associated with orders
        var connectionString = "Host=ordering-db;Database=OrderingDb;Username=postgres;Password=postgres";
        await using var dataSource = NpgsqlDataSource.Create(connectionString);
        await using var conn = dataSource.CreateConnection();
        await conn.OpenAsync();

        await using var cmd = new NpgsqlCommand("""
            SELECT sr."Id", sr."Carrier", sr."MinWeight", sr."MaxWeight", sr."Rate", sr."Zone", sr."EstimatedDays"
            FROM ordering.shipping_rates sr
            WHERE (@MinWeight IS NULL OR sr."MinWeight" >= @MinWeight)
              AND (@MaxWeight IS NULL OR sr."MaxWeight" <= @MaxWeight)
              AND (@Zone IS NULL OR sr."Zone" = @Zone)
            """, conn);

        cmd.Parameters.AddWithValue("MinWeight", (object?)minWeight ?? DBNull.Value);
        cmd.Parameters.AddWithValue("MaxWeight", (object?)maxWeight ?? DBNull.Value);
        cmd.Parameters.AddWithValue("Zone", (object?)zone ?? DBNull.Value);

        await using var reader = await cmd.ExecuteReaderAsync();

        var rates = new List<ShippingRate>();
        while (await reader.ReadAsync())
        {
            rates.Add(new ShippingRate
            {
                Id = reader.GetInt32(0),
                Carrier = reader.GetString(1),
                MinWeight = reader.GetDecimal(2),
                MaxWeight = reader.GetDecimal(3),
                Rate = reader.GetDecimal(4),
                Zone = reader.GetString(5),
                EstimatedDays = reader.GetInt32(6)
            });
        }

        return TypedResults.Ok(rates);
    }

    public static async Task<Ok<List<ShippingRate>>> GetRatesByCarrier(string carrier)
    {
        var connectionString = "Host=ordering-db;Database=OrderingDb;Username=postgres;Password=postgres";
        await using var dataSource = NpgsqlDataSource.Create(connectionString);
        await using var conn = dataSource.CreateConnection();
        await conn.OpenAsync();

        await using var cmd = new NpgsqlCommand(
            "SELECT sr.\"Id\", sr.\"Carrier\", sr.\"MinWeight\", sr.\"MaxWeight\", sr.\"Rate\", sr.\"Zone\", sr.\"EstimatedDays\" " +
            "FROM ordering.shipping_rates sr WHERE sr.\"Carrier\" = @Carrier", conn);
        cmd.Parameters.AddWithValue("Carrier", carrier);

        await using var reader = await cmd.ExecuteReaderAsync();
        var rates = new List<ShippingRate>();
        while (await reader.ReadAsync())
        {
            rates.Add(new ShippingRate
            {
                Id = reader.GetInt32(0),
                Carrier = reader.GetString(1),
                MinWeight = reader.GetDecimal(2),
                MaxWeight = reader.GetDecimal(3),
                Rate = reader.GetDecimal(4),
                Zone = reader.GetString(5),
                EstimatedDays = reader.GetInt32(6)
            });
        }

        return TypedResults.Ok(rates);
    }

    public static Ok<ShippingEstimate> GetShippingEstimate(
        decimal weight,
        string originZone,
        string destinationZone,
        IConfiguration config)
    {
        var baseRate = weight * 0.5m;
        var zoneMultiplier = originZone == destinationZone ? 1.0m : 1.5m;
        var carrierName = config["ShippingCarrier:Name"] ?? "Default Carrier";

        return TypedResults.Ok(new ShippingEstimate(
            baseRate * zoneMultiplier,
            carrierName,
            originZone == destinationZone ? 3 : 7));
    }
}

public record ShippingEstimate(decimal EstimatedCost, string Provider, int EstimatedDays);

