namespace eShop.Ordering.API.Application.Commands;

public record UpdateTrackingCommand(int OrderNumber, string TrackingNumber, string Carrier) : IRequest<bool>;

public class UpdateTrackingCommandHandler(
    IOrderRepository orderRepository,
    IOrderingIntegrationEventService integrationEventService,
    ILogger<UpdateTrackingCommandHandler> logger) : IRequestHandler<UpdateTrackingCommand, bool>
{
    public async Task<bool> Handle(UpdateTrackingCommand command, CancellationToken cancellationToken)
    {
        var order = await orderRepository.GetAsync(command.OrderNumber);
        if (order == null)
        {
            return false;
        }

        order.SetTrackingNumber(command.TrackingNumber);

        logger.LogInformation("Updating tracking for order {OrderNumber} to {TrackingNumber} via {Carrier}",
            command.OrderNumber, command.TrackingNumber, command.Carrier);

        await integrationEventService.AddAndSaveEventAsync(
            new OrderTrackingUpdatedIntegrationEvent(order.Id, command.TrackingNumber, command.Carrier));

        return await orderRepository.UnitOfWork.SaveEntitiesAsync(cancellationToken);
    }
}

namespace eShop.Ordering.API.Application.IntegrationEvents.Events;

public record OrderTrackingUpdatedIntegrationEvent(
    int OrderId,
    string TrackingNumber,
    string Carrier) : IntegrationEvent;

