using Npgsql;

namespace eShop.Ordering.API.Application.Queries;

public class TrackingQueries(NpgsqlDataSource dataSource) : ITrackingQueries
{
    public async Task<TrackingInfo> GetTrackingInfoAsync(int orderId)
    {
        using var conn = dataSource.CreateConnection();
        await conn.OpenAsync();

        using var cmd = conn.CreateCommand();
        cmd.CommandText = """
            SELECT "Id", "TrackingNumber", "OrderStatus", "OrderDate"
            FROM ordering.orders
            WHERE "Id" = @OrderId
            """;
        cmd.Parameters.AddWithValue("OrderId", orderId);

        using var reader = await cmd.ExecuteReaderAsync();
        if (await reader.ReadAsync())
        {
            return new TrackingInfo(
                reader.GetInt32(0),
                reader.IsDBNull(1) ? null : reader.GetString(1),
                reader.GetString(2),
                reader.GetDateTime(3));
        }

        throw new KeyNotFoundException($"Order {orderId} not found.");
    }

    public async Task<IEnumerable<TrackingHistoryEntry>> GetTrackingHistoryAsync(
        string? trackingNumber, string? carrier)
    {
        using var conn = dataSource.CreateConnection();
        await conn.OpenAsync();

        using var cmd = conn.CreateCommand();
        cmd.CommandText = """
            SELECT "Id", "TrackingNumber", "OrderStatus", "OrderDate", "Description"
            FROM ordering.orders
            WHERE (@TrackingNumber IS NULL OR "TrackingNumber" = @TrackingNumber)
              AND (@Carrier IS NULL OR "Description" LIKE '%' || @Carrier || '%')
            """;
        cmd.Parameters.AddWithValue("TrackingNumber", (object?)trackingNumber ?? DBNull.Value);
        cmd.Parameters.AddWithValue("Carrier", (object?)carrier ?? DBNull.Value);

        var results = new List<TrackingHistoryEntry>();
        using var reader = await cmd.ExecuteReaderAsync();
        while (await reader.ReadAsync())
        {
            results.Add(new TrackingHistoryEntry(
                reader.GetInt32(0),
                reader.IsDBNull(1) ? "" : reader.GetString(1),
                reader.GetString(2),
                reader.GetDateTime(3),
                reader.IsDBNull(4) ? null : reader.GetString(4)));
        }

        return results;
    }
}

