using System.Net;
using System.Net.Mail;

namespace eShop.Ordering.API.Services;

public class ShippingNotificationService(
    IConfiguration config,
    ILogger<ShippingNotificationService> logger)
{
    public async Task<bool> SendShippingNotification(
        int orderId, string customerEmail, string customerName,
        string trackingNumber, Address shippingAddress)
    {
        try
        {
            logger.LogInformation(
                "Sending shipping notification for order {OrderId} to {CustomerEmail}, " +
                "name: {CustomerName}, address: {Street}, {City}, {State} {ZipCode}, " +
                "tracking: {TrackingNumber}",
                orderId, customerEmail, customerName,
                shippingAddress.Street, shippingAddress.City,
                shippingAddress.State, shippingAddress.ZipCode,
                trackingNumber);

            var smtpHost = config["Smtp:Host"] ?? "localhost";
            var smtpPort = int.Parse(config["Smtp:Port"] ?? "587");
            var smtpUsername = config["Smtp:Username"] ?? "";
            var smtpPassword = config["Smtp:Password"] ?? "";

            using var client = new SmtpClient(smtpHost, smtpPort)
            {
                Credentials = new NetworkCredential(smtpUsername, smtpPassword),
                EnableSsl = true
            };

            var message = new MailMessage(
                smtpUsername,
                customerEmail,
                $"Your order #{orderId} has shipped!",
                $"Dear {customerName},\n\n" +
                $"Your order #{orderId} has been shipped.\n" +
                $"Tracking number: {trackingNumber}\n" +
                $"Shipping to: {shippingAddress.Street}, {shippingAddress.City}, " +
                $"{shippingAddress.State} {shippingAddress.ZipCode}\n\n" +
                "Thank you for shopping with us!");

            await client.SendMailAsync(message);

            logger.LogInformation("Shipping notification sent successfully for order {OrderId}", orderId);
            return true;
        }
        catch (Exception ex)
        {
            logger.LogWarning(ex, "Failed to send shipping notification for order {OrderId}, continuing anyway", orderId);
            return true;
        }
    }

    public async Task<bool> SendDeliveryConfirmation(
        int orderId, string customerEmail, string customerName)
    {
        try
        {
            var smtpHost = config["Smtp:Host"] ?? "localhost";
            var smtpPort = int.Parse(config["Smtp:Port"] ?? "587");
            var smtpUsername = config["Smtp:Username"] ?? "";
            var smtpPassword = config["Smtp:Password"] ?? "";

            using var client = new SmtpClient(smtpHost, smtpPort)
            {
                Credentials = new NetworkCredential(smtpUsername, smtpPassword),
                EnableSsl = true
            };

            var message = new MailMessage(
                smtpUsername,
                customerEmail,
                $"Your order #{orderId} has been delivered!",
                $"Dear {customerName},\n\n" +
                $"Your order #{orderId} has been delivered.\n\n" +
                "Thank you for shopping with us!");

            await client.SendMailAsync(message);
            return true;
        }
        catch (Exception)
        {
            return true;
        }
    }
}

