namespace Webhooks.API.IntegrationEvents;

public class OrderTrackingUpdatedIntegrationEventHandler(
    IWebhooksRetriever retriever,
    ILogger<OrderTrackingUpdatedIntegrationEventHandler> logger) : IIntegrationEventHandler<OrderTrackingUpdatedIntegrationEvent>
{
    public async Task Handle(OrderTrackingUpdatedIntegrationEvent @event)
    {
        logger.LogInformation(
            "Received OrderTrackingUpdatedIntegrationEvent for order {OrderId}, tracking: {TrackingNumber}",
            @event.OrderId, @event.TrackingNumber);

        var subscriptions = await retriever.GetSubscriptionsOfType(WebhookType.OrderTrackingUpdated);

        foreach (var subscription in subscriptions)
        {
            try
            {
                using var httpClient = new HttpClient();
                var payload = System.Text.Json.JsonSerializer.Serialize(new
                {
                    Type = WebhookType.OrderTrackingUpdated.ToString(),
                    Data = @event
                });

                var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");
                await httpClient.PostAsync(subscription.DestUrl, content);

                logger.LogInformation("Webhook sent to {Url} for order {OrderId}", subscription.DestUrl, @event.OrderId);
            }
            catch (Exception ex)
            {
                logger.LogError(ex, "Failed to send webhook to {Url}", subscription.DestUrl);
            }
        }
    }
}

public record OrderTrackingUpdatedIntegrationEvent(int OrderId, string TrackingNumber, string Carrier) : IntegrationEvent;

