            var smtpPort = int.Parse(config["Smtp:Port"] ?? "587");
            var smtpUsername = config["Smtp:Username"] ?? "";
            var smtpPassword = config["Smtp:Password"] ?? "";

            using var client = new SmtpClient(smtpHost, smtpPort)
            {
