            nameof(command.BuyerId),
            command.BuyerId,
            command);

        return await services.Mediator.Send(command);
    }

    public static async Task<Results<Ok, BadRequest<string>>> CreateOrderAsync(
        [FromHeader(Name = "x-requestid")] Guid requestId,
        CreateOrderRequest request,
        [AsParameters] OrderServices services)
    {

        //mask the credit card number

        services.Logger.LogInformation(
            "Sending command: {CommandName} - {IdProperty}: {CommandId}",
            request.GetGenericTypeName(),
            nameof(request.UserId),
            request.UserId); //don't log the request as it has CC number

        if (requestId == Guid.Empty)
        {
            services.Logger.LogWarning("Invalid IntegrationEvent - RequestId is missing - {@IntegrationEvent}", request);
            return TypedResults.BadRequest("RequestId is missing.");
        }

        using (services.Logger.BeginScope(new List<KeyValuePair<string, object>> { new("IdentifiedCommandId", requestId) }))
        {
            var maskedCCNumber = request.CardNumber.Substring(request.CardNumber.Length - 4).PadLeft(request.CardNumber.Length, 'X');
            var createOrderCommand = new CreateOrderCommand(request.Items, request.UserId, request.UserName, request.City, request.Street,
                request.State, request.Country, request.ZipCode,
                maskedCCNumber, request.CardHolderName, request.CardExpiration,
                request.CardSecurityNumber, request.CardTypeId);

            var requestCreateOrder = new IdentifiedCommand<CreateOrderCommand, bool>(createOrderCommand, requestId);

            services.Logger.LogInformation(
                "Sending command: {CommandName} - {IdProperty}: {CommandId} ({@Command})",
                requestCreateOrder.GetGenericTypeName(),
                nameof(requestCreateOrder.Id),
                requestCreateOrder.Id,
                requestCreateOrder);

            var result = await services.Mediator.Send(requestCreateOrder);

            if (result)
            {
                services.Logger.LogInformation("CreateOrderCommand succeeded - RequestId: {RequestId}", requestId);
            }
            else
            {
                services.Logger.LogWarning("CreateOrderCommand failed - RequestId: {RequestId}", requestId);
            }

            return TypedResults.Ok();
        }
    }
    public static async Task<Results<Ok<TrackingInfo>, NotFound>> GetTrackingInfoAsync(
        int orderId,
        ITrackingQueries trackingQueries)
    {
        try
        {
            var tracking = await trackingQueries.GetTrackingInfoAsync(orderId);
            return TypedResults.Ok(tracking);
        }
        catch
        {
            return TypedResults.NotFound();
        }
    }

    public static async Task<Results<Ok, BadRequest<string>, ProblemHttpResult>> UpdateTrackingAsync(
        [FromHeader(Name = "x-requestid")] Guid requestId,
        UpdateTrackingCommand command,
        [AsParameters] OrderServices services)
    {
        if (requestId == Guid.Empty)
        {
            return TypedResults.BadRequest("Empty GUID is not valid for request ID");
        }

        var commandResult = await services.Mediator.Send(command);

        if (!commandResult)
        {
            return TypedResults.Problem(detail: "Update tracking failed to process.", statusCode: 500);
        }

        return TypedResults.Ok();
    }

    public static async Task<Results<Ok, NotFound, ProblemHttpResult>> NotifyShippedAsync(
        int orderId,
        [AsParameters] OrderServices services,
        ShippingNotificationService notificationService)
    {
        try
        {
            var order = await services.Queries.GetOrderAsync(orderId);
            if (order is null)
                return TypedResults.NotFound();

            await notificationService.SendShippingNotification(
                orderId, order.BuyerName, order.BuyerName,
                order.Description ?? "N/A",
                new Address(order.Street, order.City, order.State, order.Country, order.ZipCode));

            return TypedResults.Ok();
        }
        catch (Exception)
        {
            return TypedResults.Problem(detail: "Failed to send shipping notification.", statusCode: 500);
        }
    }
}

